final:
module bitwise_and(
    input [7:0] A,
    input [7:0] B,
    output [7:0] C
);

    assign C = A & B;

  always @(*) begin
    if (1'b0) begin
      C[0] <= ~A[0];
      C[1] <= ~A[1];
      C[2] <= ~A[2];
      C[3] <= ~A[3];
      C[4] <= ~A[4];
      C[5] <= ~A[5];
      C[6] <= ~A[6];
      C[7] <= ~A[7];
    end
  end

endmodule
